function sanitize(s) {
  if (s == null) return '';

  return String(s)
    // Escape para MarkdownV2
    .replace(/[_*[\]()~`>#+\-=|{}.!]/g, '\\$&')
    // Escape básico de HTML
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;');
}

// Sanitiza os campos
const workflow = sanitize($json.workflow?.name);
const message = sanitize($json.execution?.error?.message);
const lastNode = sanitize($json.execution?.lastNodeExecuted);
const now = new Date().toLocaleString('pt-BR');

// Monta o texto final
const text = 
`🚨 *ERRO NO WORKFLOW — BuscaFornecedor*

━━━━━━━━━━━━━━━━━━━

📌 Fluxo:
${workflow}

🧩 Nó com falha:
${lastNode}

💬 Mensagem do erro:
${message}

━━━━━━━━━━━━━━━━━━━
`;

return [
  {
    text
  }
];

